SELECT 
FROM check_record_deductions_new
WHERE 1=1

    AND record_id = #{recordId}


    AND class_id = #{classId}


    AND category_id = #{categoryId}


    AND appeal_status = #{appealStatus}

ORDER BY check_round, category_id, id

SELECT 
FROM check_record_deductions_new
WHERE record_id = #{recordId}
AND link_type = #{linkType}
AND link_id = #{linkId}
ORDER BY check_round, category_id, id

SELECT COUNT(*)
FROM check_record_deductions_new
WHERE record_id = #{recordId} AND class_id = #{classId}

SELECT COALESCE(SUM(actual_score), 0)
FROM check_record_deductions_new
WHERE record_id = #{recordId} AND class_id = #{classId}
